+    #[test]
+    fn minimax_with_single_defender_returns_that_action() {
+        let entries = vec![
+            LossEntry {
+                attacker_action: atk("a1"),
+                defender_action: atk("d1"),
+                dimension: LossDimension::UserHarm,
+                loss_millionths: 800_000,
+            },
+            LossEntry {
+                attacker_action: atk("a2"),
+                defender_action: atk("d1"),
+                dimension: LossDimension::UserHarm,
+                loss_millionths: 200_000,
